import (
	"context"
	"encoding/json"
	"errors"
	"net/http"

	"github.com/openmeterio/openmeter/pkg/framework/transport/httptransport/encoder"
)

var encodeResponse encoder.ResponseEncoder[MyResponse] = func(
	ctx context.Context, w http.ResponseWriter, r *http.Request, resp MyResponse,
) error {
	w.Header().Set("Content-Type", "application/json")
	return json.NewEncoder(w).Encode(resp)
}

var encodeError encoder.ErrorEncoder = func(
	ctx context.Context, err error, w http.ResponseWriter, r *http.Request,
) bool {
	var ve *MyDomainError
	if errors.As(err, &ve) {
		http.Error(w, ve.Error(), http.StatusBadRequest)
		return true
	}
	return false
}
